import asyncio
from dataclasses import dataclass
from enum import Enum
from typing import Dict, List, Callable


class CommunicationType(Enum):
    DIRECT = "direct"
    BROADCAST = "broadcast"
    REQUEST = "request"


@dataclass
class Message:
    sender: str
    receiver: str
    content: dict       # structured payload — r1
    msg_type: CommunicationType
    correlation_id: str


class MessageBus:
    def __init__(self, handler_timeout_seconds: int = 60):
        self.subscribers: Dict[str, List[Callable]] = {}
        self.history: List[Message] = []
        self.timeout = handler_timeout_seconds

    def subscribe(self, name: str, handler: Callable):
        self.subscribers.setdefault(name, []).append(handler)

    async def send(self, msg: Message):
        self.history.append(msg)
        targets = (
            [n for n in self.subscribers if n != msg.sender]
            if msg.msg_type is CommunicationType.BROADCAST
            else [msg.receiver]
        )
        for name in targets:
            for h in self.subscribers.get(name, []):
                await asyncio.wait_for(h(msg), timeout=self.timeout)  # r2

async def _parallel(self, task, plan):
    async def run_one(assignment):
        agent = self.agents[assignment["agent"]]
        if self.tokens_used(agent.name) >= agent.budget_tokens:
            return {"agent": agent.name, "error": "budget_exhausted"}
        return await asyncio.wait_for(agent.respond(assignment["task"]), timeout=self.timeout)

    results = await asyncio.gather(*[run_one(a) for a in plan["assignments"]])
    return await self._synthesize(task, results)
